#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 800
#define H 600
#define S 0.001f

typedef float v3[3];
void sub(v3 r, v3 a, v3 b) { r[0]=a[0]-b[0]; r[1]=a[1]-b[1]; r[2]=a[2]-b[2]; }
void add(v3 r, v3 a, v3 b) { r[0]=a[0]+b[0]; r[1]=a[1]+b[1]; r[2]=a[2]+b[2]; }
float dot(v3 a, v3 b) { return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
void nrm(v3 v) { float l=sqrtf(v[0]*v[0]+v[1]*v[1]+v[2]*v[2]); if(l>0){v[0]/=l;v[1]/=l;v[2]/=l;} }

float sph(v3 ro, v3 rd, v3 c, float r, v3 hp, v3 hn) {
    v3 oc; sub(oc, ro, c);
    float b = dot(oc, rd)*2, d = b*b - 4*(dot(oc,oc)-r*r);
    if(d<0) return 0;
    float t = (-b - sqrtf(d))/(2);
    if(t<S) t = (-b + sqrtf(d))/(2);
    if(t<S) return 0;
    hp[0]=ro[0]+rd[0]*t; hp[1]=ro[1]+rd[1]*t; hp[2]=ro[2]+rd[2]*t;
    sub(hn, hp, c); nrm(hn);
    return t;
}

int main() {
    int i, j, k;
    float *img = malloc(W*H*3*sizeof(float));
    v3 ro = {0,0,-1.5f};
    float as = (float)W/H;

    fprintf(stderr, "Rendering...\n");

    int idx = 0;
    for(j=0; j<H; j++) {
        float vy = 1 - 2.0f*j/(H-1);
        for(i=0; i<W; i++) {
            float ux = (2.0f*i/(W-1)-1)*as;
            v3 rd = {ux, vy, 1}; nrm(rd);

            // Sky color based on ray direction
            float t = (rd[1] + 1.0f) * 0.5f;  // sky_color input
            float r = 1.0f - 0.5f*t;
            float g = 1.0f - 0.3f*t;
            float b = 1.0f - t;

            img[idx++]=r; img[idx++]=g; img[idx++]=b;
        }
        if(j%60==0) fprintf(stderr,"\rProgress: %.1f%%",100.*j/H);
    }

    fprintf(stderr,"\rProgress: 99.8%%\n");
    fprintf(stderr,"Rendering complete\n");

    FILE *fp = fopen("image.ppm","w");
    fprintf(fp,"P3\n%d %d\n255\n",W,H);
    for(i=0;i<W*H*3;i+=3)
        fprintf(fp,"%d %d %d\n",(int)(img[i]*255.99f),(int)(img[i+1]*255.99f),(int)(img[i+2]*255.99f));
    fclose(fp);

    fprintf(stderr,"Wrote image to image.ppm\n");
    fprintf(stderr,"Done.\n");
    free(img);
    return 0;
}
ENDPROG
